import React from 'react';
import Piece from './piece';
import { piece } from '../types/Piece';

export default function Chessboard() {
    const size = 8; 
    let chessboard: (piece | null)[][] = Array.from({ length: size }, () => Array(size).fill(null));

    chessboard[1][3] = { position: { row: 1, col: 3 }, image: '/Chess_plt45.svg', type: 'pawn', posibleMoves: [{ dx: 0, dy: 1, repeat: false }, { dx: 0, dy: 1, repeat: false }] }; 
    console.log(chessboard);
    return (
        <div className="chessboard">
           {Array.from({ length: size }).map((_, row) => (
                <div key={row} className="flex">
                    {Array.from({ length: size }).map((_, col) => {
                        const isWhite = (row + col) % 2 === 0;
                        return (
                            <div
                                key={col}
                                className={`chessboard-square ${isWhite ? 'bg-white' : 'bg-purple-900'} w-24 h-24`}
                            >
                                {chessboard[row][col] && (
                                    <Piece image={chessboard[row][col].image} position={chessboard[row][col].position} type={chessboard[row][col].type} posibleMoves={chessboard[row][col].posibleMoves} />
                                )}

                            </div>
                        );
                    })}
                </div>
            ))}
        </div>
    )
}