import { useState } from 'react';
import { piece } from '../types/Piece';

export default function Piece({ image, position, posibleMoves }: piece) {
    const [isSelected, setIsSelected] = useState(false);

    const handleClick = () => {
        setIsSelected(!isSelected);
    };

    return (
        <div className={`piece w-24 h-24 ${isSelected ? 'selected' : ''}`}
             style={{ backgroundImage: `url(${image})`,
             backgroundRepeat: 'no-repeat', backgroundPosition: `50% 50%`,
             backgroundSize: '100% 100%'}} onClick={handleClick}>

        </div>
    );
}